import styled from "styled-components";

import backgroundImage from '../../img/ContactForm/bg.jpg'

const ContactForm = ({ id }) => {
  return (
    <ContactFormContainer id={id}>
      <h3> Do you want to ask me a question? </h3>
      <h4> Use a contact form listed below </h4>
      <Form>
        Name: <input />
        Email: <input />
        Message: <input />
      </Form>
    </ContactFormContainer>
  )
}

const ContactFormContainer = styled.section`
  padding: 5em;
  background-size: cover;

  color: white;

  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  row-gap: 1em;

  position: relative;
  &:before {
    content: "";
    position: absolute;
    z-index: -1;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    background: url(${backgroundImage}) center center no-repeat;
    background-size: cover;
    filter: brightness(0.3);
  }

  & h3, h4 {
    margin: 0;
  }

  & h3 {
    font-size: 2em;
  }

  & h4 {
    font-size: 1em;
    font-weight: 400;
  }
`

const Form = styled.form`
  display: flex;
  flex-direction: column;
  row-gap: 1em;
`

export default ContactForm
